INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('What is the sum of the interior angles of a triangle?', '["180°", "360°", "90°", "270°"]', 'A', 'The sum of the interior angles of any triangle always equals 180°.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the formula for the area of a rectangle?', '["A = length × width", "A = base × height ÷ 2", "A = π × r²", "A = side²"]', 'A', 'The area of a rectangle is calculated by multiplying its length by its width: A = l × w.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('The Pythagorean theorem states that in a right triangle, a² + b² = c², where c is the:', '["Hypotenuse", "Adjacent side", "Opposite side", "Base"]', 'A', 'The hypotenuse is the longest side of a right triangle, opposite the right angle. In the Pythagorean theorem, c represents the hypotenuse.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the circumference of a circle with radius 7? (Use π ≈ 22/7)', '["44", "154", "22", "88"]', 'A', 'Circumference = 2πr = 2 × (22/7) × 7 = 44.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('What type of angle measures exactly 90°?', '["Right angle", "Acute angle", "Obtuse angle", "Straight angle"]', 'A', 'A right angle measures exactly 90°. It is formed when two perpendicular lines meet.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the area of a triangle with base 10 cm and height 6 cm?', '["30 cm²", "60 cm²", "16 cm²", "20 cm²"]', 'A', 'Area of triangle = (base × height) / 2 = (10 × 6) / 2 = 30 cm².', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the sum of interior angles of a quadrilateral?', '["360°", "180°", "270°", "540°"]', 'A', 'The sum of interior angles of any quadrilateral (four-sided polygon) is 360°.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the area of a circle with radius 5? (Use π ≈ 3.14)', '["78.5", "31.4", "25", "50"]', 'A', 'Area of circle = πr² = 3.14 × 5² = 3.14 × 25 = 78.5.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('Two lines that never intersect and are in the same plane are called:', '["Parallel lines", "Perpendicular lines", "Intersecting lines", "Skew lines"]', 'A', 'Parallel lines are lines in the same plane that never intersect and are always the same distance apart.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('A triangle with all sides equal is called:', '["Equilateral", "Isosceles", "Scalene", "Right"]', 'A', 'An equilateral triangle has all three sides of equal length, and all three interior angles are 60°.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the volume of a rectangular prism with length 4, width 3, and height 5?', '["60", "47", "24", "35"]', 'A', 'Volume of rectangular prism = length × width × height = 4 × 3 × 5 = 60 cubic units.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the perimeter of a square with side length 8 cm?', '["32 cm", "64 cm", "16 cm", "24 cm"]', 'A', 'Perimeter of a square = 4 × side = 4 × 8 = 32 cm.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('An angle measuring between 90° and 180° is called:', '["Obtuse angle", "Acute angle", "Right angle", "Reflex angle"]', 'A', 'An obtuse angle measures between 90° and 180°.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the name of the point where the three medians of a triangle meet?', '["Centroid", "Circumcenter", "Incenter", "Orthocenter"]', 'A', 'The centroid is the point where the three medians (lines from each vertex to the midpoint of the opposite side) of a triangle intersect.', 'Mathematics', 'Geometry', 'hard', 'secondary'),
('A quadrilateral with exactly one pair of parallel sides is called a:', '["Trapezoid", "Parallelogram", "Rectangle", "Rhombus"]', 'A', 'A trapezoid (or trapezium) is a quadrilateral with exactly one pair of parallel sides.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('What is the Pythagorean triple for legs 3 and 4?', '["5", "6", "7", "8"]', 'A', 'Using the Pythagorean theorem: 3² + 4² = 9 + 16 = 25 = 5². So the hypotenuse is 5.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the volume of a cylinder with radius 3 and height 7? (Use π ≈ 3.14)', '["197.82", "65.94", "94.2", "131.88"]', 'A', 'Volume of cylinder = πr²h = 3.14 × 3² × 7 = 3.14 × 9 × 7 = 197.82.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('The diagonal of a square with side s is equal to:', '["s√2", "s²", "2s", "s/√2"]', 'A', 'The diagonal of a square with side s is s√2, derived from the Pythagorean theorem: d² = s² + s² = 2s², so d = s√2.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('What is the term for a line segment from the center of a circle to any point on its boundary?', '["Radius", "Diameter", "Chord", "Arc"]', 'A', 'A radius is a line segment from the center of a circle to any point on the circle. The diameter is twice the radius.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('In coordinate geometry, what is the midpoint formula for two points (x₁, y₁) and (x₂, y₂)?', '["((x₁+x₂)/2, (y₁+y₂)/2)", "((x₂-x₁)/2, (y₂-y₁)/2)", "(x₁×x₂, y₁×y₂)", "((x₁-x₂), (y₁-y₂))"]', 'A', 'The midpoint formula gives the point exactly halfway between two points: M = ((x₁+x₂)/2, (y₁+y₂)/2).', 'Mathematics', 'Coordinate Geometry', 'medium', 'secondary'),
('What is the slope of a horizontal line?', '["0", "1", "Undefined", "-1"]', 'A', 'A horizontal line has a slope of 0 because there is no vertical change (rise = 0) as you move horizontally.', 'Mathematics', 'Coordinate Geometry', 'easy', 'secondary'),
('What is the sum of interior angles of a pentagon?', '["540°", "360°", "720°", "480°"]', 'A', 'Sum of interior angles of a polygon = (n-2) × 180°. For a pentagon (n=5): (5-2) × 180° = 3 × 180° = 540°.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('What transformation produces a mirror image of a figure?', '["Reflection", "Rotation", "Translation", "Dilation"]', 'A', 'Reflection is a transformation that flips a figure over a line (called the line of reflection), producing a mirror image.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the area of a trapezoid with parallel sides of 8 and 12, and height 5?', '["50", "60", "40", "100"]', 'A', 'Area of trapezoid = ½(b₁ + b₂) × h = ½(8 + 12) × 5 = ½ × 20 × 5 = 50.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('What is the distance formula between points (x₁, y₁) and (x₂, y₂)?', '["√((x₂-x₁)² + (y₂-y₁)²)", "√((x₂+x₁)² + (y₂+y₁)²)", "(x₂-x₁) + (y₂-y₁)", "(x₂-x₁) × (y₂-y₁)"]', 'A', 'The distance formula is derived from the Pythagorean theorem: d = √((x₂-x₁)² + (y₂-y₁)²).', 'Mathematics', 'Coordinate Geometry', 'medium', 'secondary'),
('Two triangles are similar if their corresponding angles are equal and corresponding sides are:', '["Proportional", "Equal", "Perpendicular", "Parallel"]', 'A', 'Similar triangles have equal corresponding angles and proportional corresponding sides (same shape but possibly different size).', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('What is the surface area of a cube with side length 4 cm?', '["96 cm²", "64 cm²", "48 cm²", "24 cm²"]', 'A', 'Surface area of a cube = 6 × side² = 6 × 4² = 6 × 16 = 96 cm².', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('What is the slope of a vertical line?', '["Undefined", "0", "1", "-1"]', 'A', 'A vertical line has an undefined slope because the run (horizontal change) is 0, and division by 0 is undefined.', 'Mathematics', 'Coordinate Geometry', 'easy', 'secondary'),
('What is the term for two angles that add up to 90°?', '["Complementary angles", "Supplementary angles", "Vertical angles", "Adjacent angles"]', 'A', 'Complementary angles are two angles whose sum is 90°. Supplementary angles sum to 180°.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the interior angle of a regular hexagon?', '["120°", "90°", "108°", "135°"]', 'A', 'Interior angle of regular polygon = (n-2) × 180° / n. For hexagon (n=6): (4 × 180°) / 6 = 720° / 6 = 120°.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('A polygon with 8 sides is called a(n):', '["Octagon", "Hexagon", "Heptagon", "Nonagon"]', 'A', 'An octagon has 8 sides. Hexagon = 6, heptagon = 7, nonagon = 9.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the volume of a sphere with radius 3? (Use π ≈ 3.14)', '["113.04", "37.68", "56.52", "150.72"]', 'A', 'Volume of sphere = (4/3)πr³ = (4/3) × 3.14 × 3³ = (4/3) × 3.14 × 27 = 4 × 3.14 × 9 = 113.04.', 'Mathematics', 'Geometry', 'hard', 'secondary'),
('In the coordinate plane, what is the x-coordinate of any point on the y-axis?', '["0", "1", "-1", "Undefined"]', 'A', 'Any point on the y-axis has an x-coordinate of 0, since it lies on the vertical axis where x = 0.', 'Mathematics', 'Coordinate Geometry', 'easy', 'secondary'),
('What is the term for a polygon where all sides and all angles are equal?', '["Regular polygon", "Convex polygon", "Irregular polygon", "Concave polygon"]', 'A', 'A regular polygon has all sides of equal length and all interior angles of equal measure.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('Two angles that are across from each other when two lines intersect are called:', '["Vertical angles", "Adjacent angles", "Complementary angles", "Supplementary angles"]', 'A', 'Vertical angles (also called vertically opposite angles) are equal angles formed on opposite sides of the intersection of two lines.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the length of the hypotenuse of a right triangle with legs 5 and 12?', '["13", "14", "15", "17"]', 'A', 'Using Pythagorean theorem: c² = 5² + 12² = 25 + 144 = 169, so c = √169 = 13.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('What is the term for a chord that passes through the center of a circle?', '["Diameter", "Radius", "Tangent", "Secant"]', 'A', 'A diameter is a chord that passes through the center of a circle. It is the longest chord and equals twice the radius.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What type of transformation slides a figure to a new position without changing its size or shape?', '["Translation", "Reflection", "Rotation", "Dilation"]', 'A', 'Translation is a transformation that slides every point of a figure the same distance in the same direction.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the sum of the exterior angles of any convex polygon?', '["360°", "180°", "540°", "720°"]', 'A', 'The sum of the exterior angles of any convex polygon is always 360°, regardless of the number of sides.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('What is the area of a parallelogram with base 9 cm and height 7 cm?', '["63 cm²", "32 cm²", "126 cm²", "45 cm²"]', 'A', 'Area of parallelogram = base × height = 9 × 7 = 63 cm². Note: height is perpendicular to the base.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('An angle inscribed in a semicircle always measures:', '["90°", "45°", "180°", "60°"]', 'A', 'By Thales'' theorem, any angle inscribed in a semicircle (with the diameter as its subtended arc) measures exactly 90°.', 'Mathematics', 'Geometry', 'hard', 'secondary'),
('What is the slope of the line passing through (2, 3) and (6, 11)?', '["2", "3", "4", "1"]', 'A', 'Slope = (y₂ - y₁) / (x₂ - x₁) = (11 - 3) / (6 - 2) = 8 / 4 = 2.', 'Mathematics', 'Coordinate Geometry', 'medium', 'secondary'),
('What is the term for the ratio of two similar figures'' corresponding sides?', '["Scale factor", "Ratio of areas", "Proportion", "Constant of similarity"]', 'A', 'The scale factor is the ratio of any two corresponding lengths in two similar figures.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('A triangle with no equal sides is called:', '["Scalene", "Isosceles", "Equilateral", "Right"]', 'A', 'A scalene triangle has no equal sides and no equal angles.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the lateral surface area of a cylinder with radius 4 and height 10? (Use π ≈ 3.14)', '["251.2", "502.4", "125.6", "100.48"]', 'A', 'Lateral surface area = 2πrh = 2 × 3.14 × 4 × 10 = 251.2.', 'Mathematics', 'Geometry', 'medium', 'secondary'),
('What is the y-intercept of the line y = 3x + 5?', '["5", "3", "-5", "0"]', 'A', 'In slope-intercept form y = mx + b, the y-intercept is b = 5. This is where the line crosses the y-axis.', 'Mathematics', 'Coordinate Geometry', 'easy', 'secondary'),
('What is the number of diagonals in a hexagon?', '["9", "6", "12", "15"]', 'A', 'Number of diagonals = n(n-3)/2. For hexagon (n=6): 6(6-3)/2 = 6×3/2 = 9.', 'Mathematics', 'Geometry', 'hard', 'secondary'),
('What transformation turns a figure around a fixed point?', '["Rotation", "Translation", "Reflection", "Dilation"]', 'A', 'Rotation is a transformation that turns a figure around a fixed point (center of rotation) by a specified angle.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('What is the relationship between the radius (r) and diameter (d) of a circle?', '["d = 2r", "d = r²", "d = r/2", "d = πr"]', 'A', 'The diameter of a circle is twice the radius: d = 2r, or equivalently r = d/2.', 'Mathematics', 'Geometry', 'easy', 'secondary'),
('If two parallel lines are cut by a transversal, alternate interior angles are:', '["Equal", "Supplementary", "Complementary", "Adjacent"]', 'A', 'When parallel lines are cut by a transversal, alternate interior angles are equal (congruent) to each other.', 'Mathematics', 'Geometry', 'medium', 'secondary');
